        .fub_axi_rlast(xbar_harness_csr_axi_rlast),
        .fub_axi_ruser(xbar_harness_csr_axi_ruser),
        .fub_axi_rvalid(xbar_harness_csr_axi_rvalid),
        .fub_axi_rready(xbar_harness_csr_axi_rready),

        // External side (m_axi)
        .m_axi_arid(harness_csr_mon_axi_arid),
        .m_axi_araddr(harness_csr_mon_axi_araddr),
        .m_axi_arlen(harness_csr_mon_axi_arlen),
        .m_axi_arsize(harness_csr_mon_axi_arsize),
        .m_axi_arburst(harness_csr_mon_axi_arburst),
        .m_axi_arlock(harness_csr_mon_axi_arlock),
        .m_axi_arcache(harness_csr_mon_axi_arcache),
        .m_axi_arprot(harness_csr_mon_axi_arprot),
        .m_axi_arqos(harness_csr_mon_axi_arqos),
        .m_axi_arregion(harness_csr_mon_axi_arregion),
        .m_axi_aruser(harness_csr_mon_axi_aruser),
        .m_axi_arvalid(harness_csr_mon_axi_arvalid),
        .m_axi_arready(harness_csr_mon_axi_arready),
        .m_axi_rid(harness_csr_mon_axi_rid),
        .m_axi_rdata(harness_csr_mon_axi_rdata),
        .m_axi_rresp(harness_csr_mon_axi_rresp),
        .m_axi_rlast(harness_csr_mon_axi_rlast),
        .m_axi_ruser(harness_csr_mon_axi_ruser),
        .m_axi_rvalid(harness_csr_mon_axi_rvalid),
        .m_axi_rready(harness_csr_mon_axi_rready),

        // Status (empty connector = unconnected tie-off)
        .busy(),
        .active_transactions(),
        .error_count(),
        .transaction_count(),
        .cfg_conflict_error(),

        // Monitor bus output
        .i_mon_time(i_mon_time),
        .monbus_valid(monbus_rd_valid),
        .monbus_ready(monbus_rd_ready),
        .monbus_packet(monbus_rd_packet),
        .monbus_timestamp(monbus_rd_timestamp),

        // Monitor cfg inputs
        .cfg_monitor_enable(cfg_rd_monitor_enable),
        .cfg_error_enable(cfg_rd_error_enable),
        .cfg_timeout_enable(cfg_rd_timeout_enable),
        .cfg_perf_enable(cfg_rd_perf_enable),
        .cfg_timeout_cycles(cfg_rd_timeout_cycles),
        .cfg_latency_threshold(cfg_rd_latency_threshold),
        .cfg_axi_pkt_mask(cfg_rd_axi_pkt_mask),
        .cfg_axi_err_select(cfg_rd_axi_err_select),
        .cfg_axi_error_mask(cfg_rd_axi_error_mask),
        .cfg_axi_timeout_mask(cfg_rd_axi_timeout_mask),
        .cfg_axi_compl_mask(cfg_rd_axi_compl_mask),
        .cfg_axi_thresh_mask(cfg_rd_axi_thresh_mask),
        .cfg_axi_perf_mask(cfg_rd_axi_perf_mask),
        .cfg_axi_addr_mask(cfg_rd_axi_addr_mask),
        .cfg_axi_debug_mask(cfg_rd_axi_debug_mask),

        // Address-range checker (disabled at N_ADDR_RANGES=0)
        .cfg_addr_check_enable(1'b0),
        .cfg_addr_range_enable(1'b0),
        .cfg_addr_range_low({32{1'b0}}),
        .cfg_addr_range_high({32{1'b0}}),

        // Perfmon Stage A/B (tied off -- no window driven)
        .cfg_start_event_sel(3'b111),
        .cfg_end_event_sel(3'b111),
        .cfg_start_trigger(1'b0),
        .cfg_end_trigger(1'b0),
        .cfg_window_force_close(1'b0),
        .window_active(),
        .window_cycles(),
        .perf_prod_cycles(),
        .perf_bp_cycles(),
        .perf_starv_cycles(),
        .perf_idle_cycles(),
        .perf_beat_count(),
        .perf_byte_count(),
        .perf_burst_count()
    );

    // AXI4-to-AXI4-Lite converter shim
    axi4_to_axil4_wr #(
        .AXI_ID_WIDTH(8),
        .AXI_ADDR_WIDTH(32),
        .AXI_DATA_WIDTH(32),
        .AXI_USER_WIDTH(1),
        .SKID_DEPTH_AW(2),
        .SKID_DEPTH_W(4),
        .SKID_DEPTH_B(2)
    ) u_harness_csr_axil_converter_wr (
        // Clocks and resets
        .aclk(aclk),
        .aresetn(aresetn),

        // AXI4 write channels (from crossbar)
        .s_axi_awid(harness_csr_mon_axi_awid),
        .s_axi_awaddr(harness_csr_mon_axi_awaddr),
        .s_axi_awlen(harness_csr_mon_axi_awlen),
        .s_axi_awsize(harness_csr_mon_axi_awsize),
        .s_axi_awburst(harness_csr_mon_axi_awburst),
        .s_axi_awlock(harness_csr_mon_axi_awlock),
        .s_axi_awcache(harness_csr_mon_axi_awcache),
        .s_axi_awprot(harness_csr_mon_axi_awprot),
        .s_axi_awqos(harness_csr_mon_axi_awqos),
        .s_axi_awregion(harness_csr_mon_axi_awregion),
        .s_axi_awuser(harness_csr_mon_axi_awuser),
        .s_axi_awvalid(harness_csr_mon_axi_awvalid),
        .s_axi_awready(harness_csr_mon_axi_awready),
        .s_axi_wdata(harness_csr_mon_axi_wdata),
        .s_axi_wstrb(harness_csr_mon_axi_wstrb),
        .s_axi_wlast(harness_csr_mon_axi_wlast),
        .s_axi_wuser(harness_csr_mon_axi_wuser),
        .s_axi_wvalid(harness_csr_mon_axi_wvalid),
        .s_axi_wready(harness_csr_mon_axi_wready),
        .s_axi_bid(harness_csr_mon_axi_bid),
        .s_axi_bresp(harness_csr_mon_axi_bresp),
        .s_axi_buser(harness_csr_mon_axi_buser),
        .s_axi_bvalid(converter_bvalid),
        .s_axi_bready(converter_bready),

        // AXI4-Lite master write interface (to external slave)
        .m_axil_awaddr(harness_csr_axi_awaddr),
        .m_axil_awprot(harness_csr_axi_awprot),
        .m_axil_awvalid(harness_csr_axi_awvalid),
        .m_axil_awready(harness_csr_axi_awready),
        .m_axil_wdata(harness_csr_axi_wdata),
        .m_axil_wstrb(harness_csr_axi_wstrb),
        .m_axil_wvalid(harness_csr_axi_wvalid),
        .m_axil_wready(harness_csr_axi_wready),
        .m_axil_bresp(harness_csr_axi_bresp),
        .m_axil_bvalid(harness_csr_axi_bvalid),
        .m_axil_bready(harness_csr_axi_bready)
    );

    axi4_to_axil4_rd #(
        .AXI_ID_WIDTH(8),
        .AXI_ADDR_WIDTH(32),
        .AXI_DATA_WIDTH(32),
        .AXI_USER_WIDTH(1),
        .SKID_DEPTH_AR(2),
        .SKID_DEPTH_R(2)
    ) u_harness_csr_axil_converter_rd (
        // Clocks and resets
        .aclk(aclk),
        .aresetn(aresetn),

        // AXI4 read channels (from crossbar)
        .s_axi_arid(harness_csr_mon_axi_arid),
        .s_axi_araddr(harness_csr_mon_axi_araddr),
        .s_axi_arlen(harness_csr_mon_axi_arlen),
        .s_axi_arsize(harness_csr_mon_axi_arsize),
        .s_axi_arburst(harness_csr_mon_axi_arburst),
        .s_axi_arlock(harness_csr_mon_axi_arlock),
        .s_axi_arcache(harness_csr_mon_axi_arcache),
        .s_axi_arprot(harness_csr_mon_axi_arprot),
        .s_axi_arqos(harness_csr_mon_axi_arqos),
        .s_axi_arregion(harness_csr_mon_axi_arregion),
        .s_axi_aruser(harness_csr_mon_axi_aruser),
        .s_axi_arvalid(harness_csr_mon_axi_arvalid),
        .s_axi_arready(harness_csr_mon_axi_arready),
        .s_axi_rid(harness_csr_mon_axi_rid),
        .s_axi_rdata(harness_csr_mon_axi_rdata),
        .s_axi_rresp(harness_csr_mon_axi_rresp),
        .s_axi_rlast(converter_rlast),
        .s_axi_ruser(harness_csr_mon_axi_ruser),
        .s_axi_rvalid(converter_rvalid),
        .s_axi_rready(converter_rready),

        // AXI4-Lite master read interface (to external slave)
        .m_axil_araddr(harness_csr_axi_araddr),
        .m_axil_arprot(harness_csr_axi_arprot),
        .m_axil_arvalid(harness_csr_axi_arvalid),
        .m_axil_arready(harness_csr_axi_arready),
        .m_axil_rdata(harness_csr_axi_rdata),
        .m_axil_rresp(harness_csr_axi_rresp),
        .m_axil_rvalid(harness_csr_axi_rvalid),
        .m_axil_rready(harness_csr_axi_rready)
    );

    // Wire converter outputs back to shim's crossbar-facing interface
    assign harness_csr_mon_axi_bvalid = converter_bvalid;
    assign converter_bready = harness_csr_mon_axi_bready;
    assign harness_csr_mon_axi_rvalid = converter_rvalid;
    assign converter_rready = harness_csr_mon_axi_rready;
    assign harness_csr_mon_axi_rlast = converter_rlast;

endmodule : harness_csr_adapter
